import React from 'react';
import { Link } from 'react-router-dom';

const PleadingCard = ({ title, description, date, status, route }) => {
  const getStatusColor = (status) => {
    switch (status.toLowerCase()) {
      case 'new':
        return 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-300';
      case 'important':
        return 'bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-300';
      case 'updated':
        return 'bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-300';
      default:
        return 'bg-gray-100 text-gray-800 dark:bg-gray-700 dark:text-gray-300';
    }
  };

  return (
    <Link
      to={route}
      className="block p-6 bg-white dark:bg-gray-800 rounded-lg shadow hover:shadow-md transition-shadow duration-200"
    >
      <div className="flex justify-between items-start">
        <div className="space-y-2">
          <h3 className="text-xl font-semibold text-gray-900 dark:text-white">
            {title}
          </h3>
          <p className="text-gray-600 dark:text-gray-400">
            {description}
          </p>
        </div>
        <span className={`px-3 py-1 text-sm font-medium rounded-full ${getStatusColor(status)}`}>
          {status}
        </span>
      </div>
      <div className="mt-4 text-sm text-gray-500 dark:text-gray-400">
        {date}
      </div>
    </Link>
  );
};

export default PleadingCard;
